const body = $json.body && typeof $json.body === 'object' ? $json.body : $json;

if (!body || typeof body !== 'object') {
  throw new Error('Request body must be valid JSON.');
}

const tenantId = String(body.tenant_id || body.tenantId || '').trim();
const sourceKey = String(body.source_key || body.sourceKey || '').trim();
const sourceType = String(body.source_type || body.sourceType || 'document').trim();
const sourceText = String(body.source_text || body.sourceText || body.text || body.content || '').trim();
const sourceMetadata = body.metadata && typeof body.metadata === 'object' ? body.metadata : {};
const openai_api_key = String(body.openai_api_key || $env.OPENAI_API_KEY || '');
const chunkSizeInput = Number(body.kb_chunk_size || 900);
const overlapInput = Number(body.kb_chunk_overlap || 120);

if (!tenantId) {
  throw new Error('tenant_id is required.');
}

if (!sourceKey) {
  throw new Error('source_key is required.');
}

if (!sourceText) {
  throw new Error('source_text or text is required and must be non-empty.');
}

return [{
  json: {
    tenant_id: tenantId,
    source_type: sourceType,
    source_key: sourceKey,
    source_text: sourceText,
    kb_chunk_size: Number.isFinite(chunkSizeInput) && chunkSizeInput > 0 ? Math.floor(chunkSizeInput) : 900,
    kb_chunk_overlap: Number.isFinite(overlapInput) && overlapInput >= 0 ? Math.floor(overlapInput) : 120,
    metadata: sourceMetadata,
    openai_api_key: String(openai_api_key || ''),
    received_at: new Date().toISOString()
  }
}];

const source = $json;
const rawText = String(source.source_text || '');
const chunkSize = Number.isFinite(Number(source.kb_chunk_size)) && Number(source.kb_chunk_size) > 0
  ? Math.floor(Number(source.kb_chunk_size))
  : 900;
const overlapRaw = Number(source.kb_chunk_overlap);
const overlap = Number.isFinite(overlapRaw) && overlapRaw >= 0
  ? Math.min(Math.floor(overlapRaw), Math.max(0, chunkSize - 1))
  : 120;

if (!rawText.trim()) {
  throw new Error('source_text is empty after normalization.');
}

const chunkStep = Math.max(1, chunkSize - overlap);
const chunks = [];
for (let i = 0, index = 0; i < rawText.length; i += chunkStep, index += 1) {
  const chunkText = rawText.substring(i, i + chunkSize);
  if (!chunkText.trim()) {
    continue;
  }

  chunks.push({
    json: {
      ...source,
      chunk_index: index,
      chunk_text: chunkText,
      chunk_char_length: chunkText.length,
      chunk_count_guess: Math.max(1, Math.ceil(rawText.length / chunkStep))
    }
  });
}

if (chunks.length === 0) {
  throw new Error('Could not create chunks from source_text.');
}

return chunks;

const source = $node['Split Into Chunks'].json || {};
const payload = $json || {};

if (payload.error) {
  throw new Error(payload.error?.message || JSON.stringify(payload.error));
}

const embedding = payload.data?.[0]?.embedding;
if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('No embedding returned by OpenAI.');
}

const model = payload.data?.[0]?.model || source.openai_embedding_model || source.tenant_settings?.openai_embedding_model || 'text-embedding-3-small';

return [{
  json: {
    ...source,
    embedding,
    openai_embedding_model: model,
    openai_usage: payload.usage || payload.data?.[0]?.usage || {}
  }
}];

